1863     else if (Pred == ICmpInst::ICMP_NE)
1864       return LazyValueInfo::True;
1865   }
1866 
1867   auto &Impl = getOrCreateImpl(M);
1868   ValueLatticeElement Result =
1869       UseBlockValue ? Impl.getValueInBlock(V, CxtI->getParent(), CxtI)
1870                     : Impl.getValueAt(V, CxtI);
1871   Tristate Ret = getPredicateResult(Pred, C, Result, DL);
1872   if (Ret != Unknown)
1873     return Ret;
1874 
1875   // Note: The following bit of code is somewhat distinct from the rest of LVI;
1876   // LVI as a whole tries to compute a lattice value which is conservatively
1877   // correct at a given location.  In this case, we have a predicate which we
1878   // weren't able to prove about the merged result, and we're pushing that
1879   // predicate back along each incoming edge to see if we can prove it
1880   // separately for each input.  As a motivating example, consider:
1881   // bb1:
1882   //   %v1 = ... ; constantrange<1, 5>
1883   //   br label %merge
1884   // bb2:
1885   //   %v2 = ... ; constantrange<10, 20>
1886   //   br label %merge
1887   // merge:
1888   //   %phi = phi [%v1, %v2] ; constantrange<1,20>
1889   //   %pred = icmp eq i32 %phi, 8
1890   // We can't tell from the lattice value for '%phi' that '%pred' is false
1891   // along each path, but by checking the predicate over each input separately,
1892   // we can.
1893   // We limit the search to one step backwards from the current BB and value.
1894   // We could consider extending this to search further backwards through the
1895   // CFG and/or value graph, but there are non-obvious compile time vs quality
1896   // tradeoffs.
1897   BasicBlock *BB = CxtI->getParent();
1898 
1899   // Function entry or an unreachable block.  Bail to avoid confusing
1900   // analysis below.
1901   pred_iterator PI = pred_begin(BB), PE = pred_end(BB);
1902   if (PI == PE)
1903     return Unknown;
1904 
1905   // If V is a PHI node in the same block as the context, we need to ask
1906   // questions about the predicate as applied to the incoming value along
1907   // each edge. This is useful for eliminating cases where the predicate is
1908   // known along all incoming edges.
1909   if (auto *PHI = dyn_cast<PHINode>(V))
1910     if (PHI->getParent() == BB) {
1911       Tristate Baseline = Unknown;
1912       for (unsigned i = 0, e = PHI->getNumIncomingValues(); i < e; i++) {
1913         Value *Incoming = PHI->getIncomingValue(i);
1914         BasicBlock *PredBB = PHI->getIncomingBlock(i);
1915         // Note that PredBB may be BB itself.
1916         Tristate Result =
1917             getPredicateOnEdge(Pred, Incoming, C, PredBB, BB, CxtI);
1918 
1919         // Keep going as long as we've seen a consistent known result for
1920         // all inputs.
1921         Baseline = (i == 0) ? Result /* First iteration */
1922                             : (Baseline == Result ? Baseline
1923                                                   : Unknown); /* All others */
1924         if (Baseline == Unknown)
1925           break;
1926       }
1927       if (Baseline != Unknown)
1928         return Baseline;
1929     }
